$root = Split-Path (Split-Path $PSScriptRoot -Parent) -Parent
if (-not (Test-Path (Join-Path $PSScriptRoot '..\words.json'))) {
    $root = Split-Path $PSScriptRoot -Parent
}
$outPath = Join-Path $root 'words.json'
$existingPath = $outPath

function New-Word($level, $chinese, [string[]]$english) {
    [PSCustomObject]@{ Level = $level; Chinese = $chinese; English = @($english) }
}

