$existing = @()
if (Test-Path $existingPath) {
    $existing = Get-Content $existingPath -Raw -Encoding UTF8 | ConvertFrom-Json
}

$seen = @{}
$list = New-Object System.Collections.ArrayList

function Add-Entry($entry) {
    $eng = $entry.English[0].ToString().Trim().ToLower()
    if ($eng.Contains(' ')) { $eng = $eng.Split(' ')[0] }
    $key = "$($entry.Level)|$eng"
    if ($seen.ContainsKey($key)) { return }
    $seen[$key] = $true
    [void]$list.Add($entry)
}

foreach ($e in $existing) { Add-Entry $e }

foreach ($row in $extra) {
    Add-Entry (New-Word $row[0] $row[1] @($row[2]))
}

