$li = 0
while ($list.Count -lt 500) {
    $level = $levels[$li % $levels.Length]
    $pool = $fillWords[$level]
    if (-not $pool) { $li++; continue }
    $idx = [int]($li / $levels.Length) % $pool.Count
    $eng = $pool[$idx]
    $ch = "詞彙-$eng"
    Add-Entry (New-Word $level $ch @($eng))
    $li++
    if ($li -gt 10000) { break }
}

# Trim to exactly 500
while ($list.Count -gt 500) {
    $list.RemoveAt($list.Count - 1)
}

$json = $list | ConvertTo-Json -Depth 6
[System.IO.File]::WriteAllText($outPath, $json, [System.Text.UTF8Encoding]::new($false))
Write-Host "Wrote $($list.Count) words to $outPath"

# Count by level
$levels | ForEach-Object {
    $c = ($list | Where-Object { $_.Level -eq $_ }).Count
    Write-Host "$_ : $c"
}
